def num_distinct(s: str, t: str) -> int:
    """Count distinct subsequences of s that equal t."""
    n, m = len(s), len(t)
    if m == 0:
        return 1
    if n == 0:
        return 0

    # dp[j] represents number of ways to form t[:j] from processed characters of s
    dp = [0] * (m + 1)
    dp[0] = 1  # empty string can be formed in 1 way

    for i in range(n):
        # Traverse backwards to avoid using updated values in same iteration
        for j in range(min(i + 1, m), 0, -1):
            if s[i] == t[j - 1]:
                dp[j] += dp[j - 1]

    return dp[m]
